import React, { useState } from "react";
import {
  Box,
  Button,
  Container,
  TextField,
  Typography,
  Paper,
  Alert,
  CircularProgress,
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import axios from "axios";
import { useAuth } from "../contexts/AuthContext";

export default function Login() {
  const navigate = useNavigate();
  const { login: loginUser } = useAuth();

  const [mobile, setMobile] = useState(""); // only digits
  const [otp, setOtp] = useState("");
  const [step, setStep] = useState(1); // 1 = enter mobile, 2 = enter OTP
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  // Validate mobile number (10 digits, 6-9 start)
  const isValidMobile = (num) => /^[6-9]\d{9}$/.test(num);

  const handleSendOtp = async () => {
    if (!isValidMobile(mobile)) {
      setError("Enter a valid 10-digit mobile number");
      return;
    }
    setLoading(true);
    setError("");
    try {
      await axios.post("http://localhost:5000/api/otp/send-otp", { mobile });
      setStep(2);
    } catch (err) {
      console.error(err);
      setError(err.response?.data?.message || "Failed to send OTP");
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyOtp = async () => {
    setLoading(true);
    setError("");
    try {
      const res = await axios.post("http://localhost:5000/api/otp/verify-otp", { mobile, otp });
      if (res.data?.success) {
        loginUser(res.data.data.user);
        localStorage.setItem("token", res.data.data.token);
        navigate("/booking");
      } else {
        setError(res.data?.message || "OTP verification failed");
      }
    } catch (err) {
      setError(err.response?.data?.message || "Server error");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="sm">
      <Paper elevation={3} sx={{ p: 4, mt: 5, borderRadius: 3 }}>
        <Typography variant="h4" align="center" gutterBottom sx={{ color: "orangered", fontWeight: "bold" }}>
          Rider App
        </Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}

        {step === 1 && (
          <>
            <TextField
              fullWidth
              type="tel"
              label="Mobile Number"
              value={mobile}
              onChange={(e) => setMobile(e.target.value.replace(/\D/g, "").slice(0, 10))}
              margin="normal"
              InputProps={{
                startAdornment: <Typography sx={{ mr: 1 }}>+91</Typography>,
              }}
              placeholder="7799231212"
            />
            <Button
              fullWidth
              variant="contained"
              sx={{ mt: 2, bgcolor: "orangered", "&:hover": { bgcolor: "darkred" } }}
              onClick={handleSendOtp}
              disabled={loading}
            >
              {loading ? <CircularProgress size={24} sx={{ color: "white" }} /> : "Send OTP"}
            </Button>
          </>
        )}

        {step === 2 && (
          <>
            <TextField
              fullWidth
              type="tel"
              label="Enter OTP"
              value={otp}
              onChange={(e) => setOtp(e.target.value.replace(/\D/g, "").slice(0, 6))}
              margin="normal"
              inputProps={{ maxLength: 6 }}
            />
            <Button
              fullWidth
              variant="contained"
              sx={{ mt: 2, bgcolor: "orangered", "&:hover": { bgcolor: "darkred" } }}
              onClick={handleVerifyOtp}
              disabled={loading}
            >
              {loading ? <CircularProgress size={24} sx={{ color: "white" }} /> : "Verify OTP"}
            </Button>
          </>
        )}

        {/* Signup button */}
        <Typography align="center" sx={{ mt: 3 }}>
          Don't have an account?{" "}
          <Button variant="text" sx={{ color: "orangered" }} onClick={() => navigate("/register")}>
            Signup
          </Button>
        </Typography>
      </Paper>
    </Container>
  );
}
